    "severity": "critical",
    "description": "The isFeatureAllowedForScope function assumes config.scope is always defined, but the interface marks it as optional (line 10). When a feature has no scope field, calling config.scope.includes(scope) will throw a TypeError. According to the function's own documentation (lines 70-72), features without a scope field should be allowed for all scopes, but the code will crash instead of returning true.",
    "fix_patch": "--- a/packages/features/feature-opt-in/config.ts
+++ b/packages/features/feature-opt-in/config.ts
@@ -73,7 +73,7 @@ export function getOptInFeaturesForScope(scope: OptInFeatureScope): OptInFeature
 export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
   const config = getOptInFeatureConfig(slug);
   if (!config) return false;
-  return config.scope.includes(scope);
+  return !config.scope || config.scope.includes(scope);
 }
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 161,
    "severity": "critical",
    "description": "The resolveFeatureState method hardcodes the feature policy to 'permissive' instead of retrieving it from the feature configuration. This violates the compliance pattern established in the config module where each feature defines its own policy. Features with 'restrictive' policies will be evaluated with 'permissive' logic, causing incorrect behavior.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -158,7 +158,8 @@ export class FeatureOptInService implements IFeatureOptInService {
       userAutoOptIn,
     });

-    const policy: OptInFeaturePolicy = "permissive";
+    const config = getOptInFeatureConfig(featureId);
+    const policy: OptInFeaturePolicy = config?.policy ?? "permissive";

     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
       globalEnabled,
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 187,
    "severity": "medium",
    "description": "The JSDoc comment at line 187 states the function 'Only returns features that are in the allowlist, globally enabled, and scoped to "user"', but the filter at line 205 is '!state.globalEnabled', which returns globally DISABLED features. For an opt-in system, this logic is correct (users opt into disabled features), but the comment is misleading and contradicts the implementation, violating documentation compliance.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -185,7 +185,7 @@ export class FeatureOptInService implements IFeatureOptInService {
   /**
    * List all opt-in features with their states for a user across teams.
-   * Only returns features that are in the allowlist, globally enabled, and scoped to "user".
+   * Only returns features that are in the allowlist, globally disabled, and scoped to "user".
    */
   async listFeaturesForUser(input: {
     userId: number;
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 88,
    "severity": "high",
    "description": "The setUserState endpoint does not validate that input.slug is a valid opt-in feature, unlike setTeamState (line 117) and setOrganizationState (line 146) which both call isOptInFeature(). This inconsistency violates the compliance pattern of slug validation across all mutation endpoints and allows invalid slugs to reach the service layer without early validation.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -93,6 +93,12 @@ export const featureOptInRouter = router({
       })
     )
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

